import { useState, useEffect } from 'react';
import { getJobs, getJobSubmissions } from '../../api/index.js';
import { Spinner, Btn, Badge, useToast } from '../../components/shared/index.jsx';

export function HRCVRankingPage() {
  const toast = useToast();
  const [jobs, setJobs] = useState([]);
  const [selectedJobId, setSelectedJobId] = useState(null);
  const [submissions, setSubmissions] = useState([]);
  const [loadingJobs, setLoadingJobs] = useState(true);
  const [loadingSubmissions, setLoadingSubmissions] = useState(false);

  useEffect(() => {
    const loadJobs = async () => {
      setLoadingJobs(true);
      try {
        const data = await getJobs();
        setJobs(Array.isArray(data) ? data : []);
        if (Array.isArray(data) && data.length > 0) {
          setSelectedJobId(data[0].id);
        }
      } catch (e) {
        toast('Failed to load jobs for CV ranking', 'error');
      }
      setLoadingJobs(false);
    };
    loadJobs();
  }, []);

  useEffect(() => {
    if (!selectedJobId) {
      setSubmissions([]);
      return;
    }

    const loadSubs = async () => {
      setLoadingSubmissions(true);
      try {
        const data = await getJobSubmissions(selectedJobId);
        setSubmissions(Array.isArray(data) ? data : []);
      } catch (e) {
        toast('Failed to load submissions for selected job', 'error');
      }
      setLoadingSubmissions(false);
    };

    loadSubs();
  }, [selectedJobId]);

  const selectedJob = jobs.find(j => j.id === selectedJobId);
  const top = submissions[0];

  return (
    <div style={{ maxWidth: 1280, margin: '0 auto', padding: '40px 32px 80px' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 28, flexWrap: 'wrap', gap: 16 }}>
        <div>
          <h2 style={{ fontSize: 22, fontWeight: 700, marginBottom: 4 }}>CV Ranking</h2>
          <p style={{ fontSize: 13.5, color: 'var(--gray-500)' }}>Pick a job and inspect candidate resumes ranked by ATS score.</p>
        </div>
      </div>

      {loadingJobs ? (
        <div style={{ textAlign: 'center', padding: 80 }}><Spinner /></div>
      ) : jobs.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 48, background: 'var(--white)', borderRadius: 24, border: '1px solid #EAECF0' }}>
          <p style={{ fontSize: 13, color: 'var(--gray-500)' }}>No recruitment jobs found. Create a job first from backend (`POST /api/recruitment/jobs/`).</p>
        </div>
      ) : (
        <>
          <div style={{ marginBottom: 20, display: 'flex', gap: 10, flexWrap: 'wrap' }}>
            {jobs.map(job => (
              <Btn
                key={job.id}
                variant={selectedJobId === job.id ? 'primary' : 'ghost'}
                onClick={() => setSelectedJobId(job.id)}
                size="sm"
              >
                {job.title} ({job.submission_count || 0})
              </Btn>
            ))}
          </div>

          <div style={{ background: 'var(--white)', borderRadius: 24, border: '1px solid #EAECF0', padding: 20, marginBottom: 20 }}>
            <h3 style={{ marginBottom: 10 }}>Job details</h3>
            <p style={{ color: 'var(--gray-500)', marginBottom: 8 }}>Title: {selectedJob?.title || '—'}</p>
            <p style={{ color: 'var(--gray-500)', marginBottom: 8 }}>Description: {selectedJob?.description ? selectedJob.description.slice(0, 180) + (selectedJob.description.length > 180 ? '...' : '') : '—'}</p>
            <p style={{ color: 'var(--gray-500)', marginBottom: 4 }}>Required skills: {selectedJob?.required_skills?.join(', ') || '—'}</p>
            <p style={{ color: 'var(--gray-500)' }}>Weights: Skills {Math.round((selectedJob?.weight_skills ?? 0) * 100)}%, Experience {Math.round((selectedJob?.weight_experience ?? 0) * 100)}%, Education {Math.round((selectedJob?.weight_education ?? 0) * 100)}%, Semantic {Math.round((selectedJob?.weight_semantic ?? 0) * 100)}%</p>
          </div>

          {loadingSubmissions ? (
            <div style={{ textAlign: 'center', padding: 80 }}><Spinner /></div>
          ) : submissions.length === 0 ? (
            <div style={{ textAlign: 'center', padding: 48, background: 'var(--white)', borderRadius: 24, border: '1px solid #EAECF0' }}>
              <p style={{ fontSize: 13, color: 'var(--gray-500)' }}>No CV submissions processed yet for this job.</p>
            </div>
          ) : (
            <>
              <div style={{ marginBottom: 16, display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 10 }}>
                <div>
                  <p style={{ margin: 0, fontSize: 13, color: 'var(--gray-500)' }}><strong>Total candidates:</strong> {submissions.length}</p>
                  <p style={{ margin: 0, fontSize: 13, color: 'var(--gray-500)' }}><strong>Top candidate:</strong> {top?.candidate_name || '-'} ({top?.ats_score?.toFixed(1) || '0.0'})</p>
                </div>
                <Badge label={`Best: ${top?.candidate_name || 'N/A'}`} color="accent" />
              </div>

              <div style={{ overflowX: 'auto', background: 'var(--white)', borderRadius: 24, border: '1px solid #EAECF0' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: 900 }}>
                  <thead style={{ background: 'var(--gray-50)' }}>
                    <tr>
                      {['Rank', 'Candidate', 'Email', 'ATS Score', 'Skills', 'Experience', 'Education', 'Semantic', 'Status'].map(h => (
                        <th key={h} style={{ padding: '12px 16px', textAlign: 'left', fontSize: 11, fontWeight: 700, color: 'var(--gray-500)', textTransform: 'uppercase', letterSpacing: '.08em', borderBottom: '1px solid #EAECF0' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {submissions.map((s, index) => (
                      <tr key={s.id} style={{ borderBottom: '1px solid #F3F4F6' }} onMouseEnter={e => e.currentTarget.style.background = 'var(--gray-50)'} onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>{index + 1}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13, fontWeight: 600 }}>{s.candidate_name || 'Anonymous'}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>{s.candidate_email || '-'}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>{s.ats_score?.toFixed(1) || '0.0'}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>{s.skills_score?.toFixed(1) || '-'}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>{s.experience_score?.toFixed(1) || '-'}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>{s.education_score?.toFixed(1) || '-'}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>{s.semantic_score?.toFixed(1) || '-'}</td>
                        <td style={{ padding: '12px 16px', fontSize: 13 }}>
                          <Badge
                            color={s.status === 'done' ? 'green' : s.status === 'processing' ? 'yellow' : 'gray'}
                            label={s.status || 'unknown'}
                          />
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </>
          )}
        </>
      )}
    </div>
  );
}
